## Edge Function para verificar estructura de tablas

```typescript
// supabase/functions/verificar-estructura-tablas/index.ts
import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

interface TableStructure {
  table_name: string;
  columns: Array<{
    column_name: string;
    data_type: string;
    is_nullable: string;
    column_default: string | null;
    character_maximum_length: number | null;
  }>;
  constraints: Array<{
    constraint_name: string;
    constraint_type: string;
    column_name: string;
    foreign_table_name: string | null;
    foreign_column_name: string | null;
  }>;
}

serve(async (req) => {
  // Handle CORS
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const supabaseClient = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    )

    const tables = ['cotizaciones', 'historial_compras', 'ordenes_trabajo'];
    const result: { [key: string]: TableStructure | { exists: false } } = {};

    for (const tableName of tables) {
      // Verificar si la tabla existe
      const { data: tableExists } = await supabaseClient
        .rpc('check_table_exists', { table_name: tableName })
        .single();

      if (!tableExists) {
        result[tableName] = { exists: false };
        continue;
      }

      // Obtener estructura de columnas
      const { data: columns, error: columnsError } = await supabaseClient
        .from('information_schema.columns')
        .select(`
          column_name,
          data_type,
          is_nullable,
          column_default,
          character_maximum_length
        `)
        .eq('table_name', tableName)
        .eq('table_schema', 'public')
        .order('ordinal_position');

      if (columnsError) {
        console.error(`Error getting columns for ${tableName}:`, columnsError);
        continue;
      }

      // Obtener constraints y foreign keys
      const { data: constraints, error: constraintsError } = await supabaseClient
        .rpc('get_table_constraints', { table_name: tableName });

      if (constraintsError) {
        console.error(`Error getting constraints for ${tableName}:`, constraintsError);
      }

      result[tableName] = {
        table_name: tableName,
        columns: columns || [],
        constraints: constraints || []
      };
    }

    return new Response(
      JSON.stringify(result),
      { 
        headers: { 
          ...corsHeaders, 
          'Content-Type': 'application/json' 
        } 
      }
    )

  } catch (error) {
    console.error('Error:', error)
    return new Response(
      JSON.stringify({ error: error.message }),
      { 
        status: 500,
        headers: { 
          ...corsHeaders, 
          'Content-Type': 'application/json' 
        }
      }
    )
  }
})
```

## Funciones SQL auxiliares necesarias

```sql
-- Función para verificar si una tabla existe
CREATE OR REPLACE FUNCTION check_table_exists(table_name text)
RETURNS boolean
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1 
    FROM information_schema.tables 
    WHERE table_schema = 'public' 
      AND table_name = $1
  );
END;
$$;

-- Función para obtener constraints de una tabla
CREATE OR REPLACE FUNCTION get_table_constraints(table_name text)
RETURNS TABLE(
  constraint_name text,
  constraint_type text,
  column_name text,
  foreign_table_name text,
  foreign_column_name text
)
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
BEGIN
  RETURN QUERY
  SELECT
    tc.constraint_name::text,
    tc.constraint_type::text,
    kcu.column_name::text,
    ccu.table_name::text,
    ccu.column_name::text
  FROM information_schema.table_constraints tc
  JOIN information_schema.key_column_usage kcu 
    ON tc.constraint_name = kcu.constraint_name
  LEFT JOIN information_schema.constraint_column_usage ccu
    ON ccu.constraint_name = tc.constraint_name
  WHERE tc.table_name = $1
    AND tc.table_schema = 'public'
  ORDER BY tc.constraint_name;
END;
$$;
```

