## Edge Function: convertir-cotizacion-v1

```typescript
// supabase/functions/convertir-cotizacion-v1/index.ts
import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

interface CotizacionItem {
  id: string
  descripcion: string
  cantidad: number
  precio_unitario: number
  precio_total: number
}

interface ConvertirCotizacionRequest {
  cotizacion_id: string
  anticipo?: number
  fecha_entrega_estimada?: string
  notas_produccion?: string
}

serve(async (req) => {
  // Handle CORS
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const supabaseClient = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    )

    const { cotizacion_id, anticipo, fecha_entrega_estimada, notas_produccion } = await req.json() as ConvertirCotizacionRequest

    if (!cotizacion_id) {
      return new Response(
        JSON.stringify({ error: 'cotizacion_id es requerido' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      )
    }

    // 1. Verificar que la cotización existe y está aprobada
    const { data: cotizacion, error: cotizacionError } = await supabaseClient
      .from('cotizaciones')
      .select(`
        *,
        cotizacion_items (*)
      `)
      .eq('id', cotizacion_id)
      .eq('estado', 'aprobada')
      .single()

    if (cotizacionError || !cotizacion) {
      return new Response(
        JSON.stringify({ 
          error: 'Cotización no encontrada o no está aprobada',
          details: cotizacionError?.message 
        }),
        { status: 404, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      )
    }

    // 2. Verificar que no se haya convertido previamente
    const { data: ordenExistente } = await supabaseClient
      .from('ordenes_trabajo')
      .select('id')
      .eq('cotizacion_id', cotizacion_id)
      .single()

    if (ordenExistente) {
      return new Response(
        JSON.stringify({ 
          error: 'Esta cotización ya fue convertida a orden de trabajo',
          orden_id: ordenExistente.id 
        }),
        { status: 409, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      )
    }

    // 3. Generar número de orden secuencial
    const { data: ultimaOrden } = await supabaseClient
      .from('ordenes_trabajo')
      .select('numero_orden')
      .order('numero_orden', { ascending: false })
      .limit(1)
      .single()

    const numeroOrden = ultimaOrden ? ultimaOrden.numero_orden + 1 : 1

    // 4. Crear transacción para historial_compras y orden_trabajo
    const { data: historialCompra, error: historialError } = await supabaseClient
      .from('historial_compras')
      .insert({
        prospecto_id: cotizacion.prospecto_id,
        cotizacion_id: cotizacion.id,
        total: cotizacion.total,
        anticipo: anticipo || 0,
        saldo: cotizacion.total - (anticipo || 0),
        estado: 'pendiente',
        fecha_venta: new Date().toISOString()
      })
      .select()
      .single()

    if (historialError) {
      return new Response(
        JSON.stringify({ 
          error: 'Error creando historial de compra',
          details: historialError.message 
        }),
        { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      )
    }

    // 5. Crear orden de trabajo
    const fechaEntrega = fecha_entrega_estimada 
      ? new Date(fecha_entrega_estimada).toISOString()
      : new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString() // 30 días por defecto

    const { data: ordenTrabajo, error: ordenError } = await supabaseClient
      .from('ordenes_trabajo')
      .insert({
        numero_orden: numeroOrden,
        cotizacion_id: cotizacion.id,
        prospecto_id: cotizacion.prospecto_id,
        historial_compra_id: historialCompra.id,
        estado: 'pendiente',
        fecha_inicio: new Date().toISOString(),
        fecha_entrega_estimada: fechaEntrega,
        total: cotizacion.total,
        anticipo: anticipo || 0,
        notas_produccion: notas_produccion || '',
        progreso: 0
      })
      .select()
      .single()

    if (ordenError) {
      // Rollback del historial si falla la orden
      await supabaseClient
        .from('historial_compras')
        .delete()
        .eq('id', historialCompra.id)

      return new Response(
        JSON.stringify({ 
          error: 'Error creando orden de trabajo',
          details: ordenError.message 
        }),
        { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      )
    }

    // 6. Crear ítems de la orden de trabajo
    const itemsOrden = cotizacion.cotizacion_items.map((item: CotizacionItem) => ({
      orden_trabajo_id: ordenTrabajo.id,
      descripcion: item.descripcion,
      cantidad: item.cantidad,
      precio_unitario: item.precio_unitario,
      precio_total: item.precio_total,
      estado: 'pendiente'
    }))

    const { error: itemsError } = await supabaseClient
      .from('orden_trabajo_items')
      .insert(itemsOrden)

    if (itemsError) {
      // Rollback completo si fallan los ítems
      await supabaseClient
        .from('ordenes_trabajo')
        .delete()
        .eq('id', ordenTrabajo.id)

      await supabaseClient
        .from('historial_compras')
        .delete()
        .eq('id', historialCompra.id)

      return new Response(
        JSON.stringify({ 
          error: 'Error creando ítems de orden',
          details: itemsError.message 
        }),
        { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      )
    }

    // 7. Actualizar estado de cotización a 'convertida'
    await supabaseClient
      .from('cotizaciones')
      .update({ estado: 'convertida' })
      .eq('id', cotizacion_id)

    // 8. Respuesta exitosa
    return new Response(
      JSON.stringify({
        success: true,
        message: 'Cotización convertida exitosamente',
        data: {
          orden_trabajo: ordenTrabajo,
          historial_compra: historialCompra,
          numero_orden: numeroOrden,
          items_creados: itemsOrden.length
        }
      }),
      { 
        status: 200, 
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      }
    )

  } catch (error) {
    console.error('Error en convertir-cotizacion-v1:', error)

    return new Response(
      JSON.stringify({ 
        error: 'Error interno del servidor',
        details: error.message 
      }),
      { 
        status: 500, 
        headers: { ...corsHeaders, 'Content-Type': 'application/json' }
      }
    )
  }
})
```

