## 1. Hook personalizado para la conversión

```tsx
// src/hooks/useConvertirCotizacion.ts
import { useState } from 'react';
import { supabase } from '../lib/supabase';

interface ConversionResult {
  success: boolean;
  ordenes_trabajo_id?: string;
  historial_compras_id?: string;
  error?: string;
}

export const useConvertirCotizacion = () => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const convertirCotizacion = async (cotizacionId: string): Promise<ConversionResult> => {
    setIsLoading(true);
    setError(null);

    try {
      const { data, error } = await supabase.functions.invoke('convertir-cotizacion-v1', {
        body: { cotizacion_id: cotizacionId }
      });

      if (error) throw error;

      setIsLoading(false);
      return { success: true, ...data };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Error desconocido';
      setError(errorMessage);
      setIsLoading(false);
      return { success: false, error: errorMessage };
    }
  };

  return {
    convertirCotizacion,
    isLoading,
    error,
    clearError: () => setError(null)
  };
};
```

