// src/components/botones/BotonConvertirOrden.tsx
import React, { useState } from 'react';
import { useConvertirCotizacion } from '../../hooks/useConvertirCotizacion';
import { CheckCircleIcon, ExclamationTriangleIcon, ArrowRightIcon } from '@heroicons/react/24/outline';

interface BotonConvertirOrdenProps {
  cotizacionId: string;
  onSuccess?: (ordenId: string, compraId: string) => void;
  onError?: (error: string) => void;
  disabled?: boolean;
  className?: string;
}

export const BotonConvertirOrden: React.FC<BotonConvertirOrdenProps> = ({
  cotizacionId,
  onSuccess,
  onError,
  disabled = false,
  className = ''
}) => {
  const { convertirCotizacion, isLoading, error } = useConvertirCotizacion();
  const [showConfirm, setShowConfirm] = useState(false);
  const [success, setSuccess] = useState(false);

  const handleConvertir = async () => {
    const result = await convertirCotizacion(cotizacionId);

    if (result.success && result.ordenes_trabajo_id && result.historial_compras_id) {
      setSuccess(true);
      onSuccess?.(result.ordenes_trabajo_id, result.historial_compras_id);

      // Auto-ocultar mensaje de éxito después de 3 segundos
      setTimeout(() => setSuccess(false), 3000);
