## 1. Actualizar hook de conversión

```tsx
// src/hooks/useConvertirCotizacion.ts
import { useState } from 'react';
import { supabase } from '../lib/supabase';

export const useConvertirCotizacion = () => {
  const [isConverting, setIsConverting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const convertirCotizacion = async (cotizacionId: string) => {
    setIsConverting(true);
    setError(null);
    setSuccess(false);

    try {
      // 1. Llamar a la Edge Function para crear orden y historial
      const { data: functionResult, error: functionError } = await supabase.functions.invoke(
        'convertir-cotizacion-v1',
        {
          body: { cotizacion_id: cotizacionId }
        }
      );

      if (functionError) {
        throw new Error(`Error en función: ${functionError.message}`);
      }

      if (!functionResult.success) {
        throw new Error(functionResult.error || 'Error desconocido en la conversión');
      }

      // 2. Actualizar estado de cotización a 'convertida'
      const { error: updateError } = await supabase
        .from('cotizaciones')
        .update({ 
          estado: 'convertida',
          fecha_actualizacion: new Date().toISOString()
        })
        .eq('id', cotizacionId);

      if (updateError) {
        throw new Error(`Error actualizando cotización: ${updateError.message}`);
      }

      setSuccess(true);
      return {
        success: true,
        ordenId: functionResult.orden_id,
        compraId: functionResult.compra_id
      };

    } catch (err: any) {
      const errorMessage = err.message || 'Error desconocido';
      setError(errorMessage);
      console.error('Error convirtiendo cotización:', err);
      return { success: false, error: errorMessage };

    } finally {
      setIsConverting(false);
    }
  };

  const resetState = () => {
    setError(null);
    setSuccess(false);
  };

  return {
    convertirCotizacion,
    isConverting,
    error,
    success,
    resetState
  };
};
```

