```typescript
// supabase/functions/convertir-cotizacion-v1/index.ts
import { createClient } from '@supabase/supabase-js';
import { corsHeaders } from '../_shared/cors.ts';

export default async function handler(req: Request) {
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const supabase = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!
    );

    const { cotizacionId } = await req.json();

    if (!cotizacionId) {
      return new Response(
        JSON.stringify({ error: 'ID de cotización requerido' }),
        { status: 400, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // ✅ VALIDAR COTIZACIÓN Y PREVENIR DUPLICADOS
    const { data: cotizacion, error: cotizacionError } = await supabase
      .from('cotizaciones')
      .select(`
        *,
        clientes(nombre, email, telefono)
      `)
      .eq('id', cotizacionId)
      .eq('estado', 'aprobada') // ✅ Solo aprobadas
      .is('convertida', false)   // ✅ No convertidas
      .single();

    if (cotizacionError || !cotizacion) {
      return new Response(
        JSON.stringify({ 
          error: 'Cotización no encontrada, no aprobada o ya convertida' 
        }),
        { status: 404, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    // ✅ TRANSACCIÓN COMPLETA CON ROLLBACK
    const { data: transactionResult, error: transactionError } = await supabase.rpc(
      'convertir_cotizacion_transaccion',
      {
        p_cotizacion_id: cotizacionId,
        p_cliente_id: cotizacion.cliente_id,
        p_total: cotizacion.total,
        p_descripcion: cotizacion.descripcion_trabajo
      }
    );

    if (transactionError) {
      console.error('Error en transacción:', transactionError);
      return new Response(
        JSON.stringify({ 
          error: 'Error interno al procesar conversión',
          details: transactionError.message 
        }),
        { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
      );
    }

    return new Response(
      JSON.stringify({ 
        success: true, 
        historial_id: transactionResult.historial_id,
        orden_id: transactionResult.orden_id 
      }),
      { status: 200, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );

  } catch (error) {
    console.error('Error general:', error);
    return new Response(
      JSON.stringify({ error: 'Error interno del servidor' }),
      { status: 500, headers: { ...corsHeaders, 'Content-Type': 'application/json' } }
    );
  }
}
```

### Solución 2: Función de Base de Datos Transaccional

```sql
-- Crear función PL/pgSQL para transacción atómica
CREATE OR REPLACE FUNCTION convertir_cotizacion_transaccion(
  p_cotizacion_id UUID,
  p_cliente_id UUID,
  p_total DECIMAL,
  p_descripcion TEXT
) RETURNS JSON
LANGUAGE plpgsql
SECURITY DEFINER
AS $$
DECLARE
  v_historial_id UUID;
  v_orden_id UUID;
  v_cotizacion_numero TEXT;
BEGIN
  -- ✅ BLOQUEAR FILA PARA PREVENIR RACE CONDITIONS
  SELECT numero INTO v_cotizacion_numero
  FROM cotizaciones 
  WHERE id = p_cotizacion_id 
    AND estado = 'aprobada' 
    AND (convertida IS FALSE OR convertida IS NULL)
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Cotización no válida para conversión';
  END IF;

  -- ✅ CREAR HISTORIAL DE COMPRA
  INSERT INTO historial_compras (
    id,
    cliente_id,
    fecha_compra,
    total,
    estado,
    cotizacion_origen_id,
    created_at
  ) VALUES (
    gen_random_uuid(),
    p_cliente_id,
    CURRENT_DATE,
    p_total,
    'pendiente',
    p_cotizacion_id,
    NOW()
  ) RETURNING id INTO v_historial_id;

  -- ✅ CREAR ORDEN DE TRABAJO
  INSERT INTO ordenes_trabajo (
    id,
    cliente_id,
    descripcion,
    estado,
    fecha_inicio,
    precio_total,
    historial_compra_id,
    created_at
  ) VALUES (
    gen_random_uuid(),
    p_cliente_id,
    p_descripcion,
    'pendiente',
    CURRENT_DATE,
    p_total,
    v_historial_id,
    NOW()
  ) RETURNING id INTO v_orden_id;

  -- ✅ MARCAR COTIZACIÓN COMO CONVERTIDA
  UPDATE cotizaciones 
  SET convertida = TRUE, updated_at = NOW()
  WHERE id = p_cotizacion_id;

  -- ✅ RETORNAR IDs GENERADOS
  RETURN json_build_object(
    'historial_id', v_historial_id,
    'orden_id', v_orden_id
  );

EXCEPTION
  WHEN OTHERS THEN
    -- ✅ ROLLBACK AUTOMÁTICO EN CASO DE ERROR
    RAISE EXCEPTION 'Error en conversión: %', SQLERRM;
END;
$$;
```

### Solución 3: Frontend Hook Mejorado

```tsx
// src/hooks/useConvertirCotizacion.ts
import { useState, useCallback, useRef } from 'react';
import { supabase } from '../lib/supabase';

interface ConvertirCotizacionResult {
  success: boolean;
  historial_id?: string;
  orden_id?: string;
  error?: string;
}

export const useConvertirCotizacion = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  // ✅ PREVENIR MÚLTIPLES LLAMADAS SIMULTÁNEAS
  const abortControllerRef = useRef<AbortController | null>(null);

  const convertir = useCallback(async (cotizacionId: string): Promise<ConvertirCotizacionResult> => {
    // ✅ CANCELAR LLAMADA ANTERIOR SI EXISTE
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    // ✅ PREVENIR DOBLE CLICK
    if (loading) {
      return { success: false, error: 'Conversión en progreso...' };
    }

    setLoading(true);
    setError(null);
    setSuccess(false);

    // ✅ NUEVO ABORT CONTROLLER
    abortControllerRef.current = new AbortController();

    try {
      const { data, error: functionError } = await supabase.functions.invoke(
        'convertir-cotizacion-v1',
        {
          body: { cotizacionId },
          signal: abortControllerRef.current.signal
        }
      );

      if (functionError) {
        throw new Error(functionError.message || 'Error en la conversión');
      }

      if (data?.error) {
        throw new Error(data.error);
      }

      // ✅ SUCCESS SOLO SI TODO SALIÓ BIEN
      setSuccess(true);
      return {
        success: true,
        historial_id: data?.historial_id,
        orden_id: data?.orden_id
      };

    } catch (err: any) {
      // ✅ NO MOSTRAR ERROR SI FUE CANCELADO
      if (err.name === 'AbortError') {
        return { success: false, error: 'Operación cancelada' };
      }

      const errorMessage = err.message || 'Error desconocido';
      setError(errorMessage);
      return { success: false, error: errorMessage };

    } finally {
      setLoading(false);
      abortControllerRef.current = null;
    }
  }, [loading]);

  // ✅ CLEANUP AL DESMONTAR
  const cleanup = useCallback(() => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    setLoading(false);
    setError(null);
    setSuccess(false);
  }, []);

  return {
    convertir,
    loading,
    error,
    success,
    cleanup
  };
};
```

