// src/components/ConvertirCotizacionButton.tsx
import { useState, useEffect } from 'react';
import { useConvertirCotizacion } from '../hooks/useConvertirCotizacion';

interface Props {
  cotizacionId: string;
  onSuccess?: () => void;
  disabled?: boolean;
}

export const ConvertirCotizacionButton = ({ 
  cotizacionId, 
  onSuccess, 
  disabled = false 
}: Props) => {
  const { convertir, loading, error, success, cleanup } = useConvertirCotizacion();
  const [convertida, setConvertida] = useState(false);

  // ✅ CLEANUP AL DESMONTAR
  useEffect(() => {
    return () => cleanup();
  }, [cleanup]);

  const handleConvertir = async () => {
    // ✅ CONFIRMACIÓN ANTES DE CONVERTIR
    const confirmacion = window.confirm(
      '¿Estás seguro de convertir esta cotización a orden de trabajo? Esta acción no se puede deshacer.'
    );

    if (!confirmacion) return;

    const result = await convertir(cotizacionId);

    if (result.success) {
      setConvertida(true);
      onSuccess?.();
    }
  };

  // ✅ BOTÓN DESHABILITADO SI YA FUE CONVERTIDA
  if (convertida || success) {
    return (
      <button 
        disabled 
        className="px-4 py-2 bg-green-600 text-white rounded opacity-50 cursor-not-allowed"
      >
        ✓ Convertida
      </button>
    );
  }

  return (
    <div className="space-y-2">
      <button
        onClick={handleConvertir}
        disabled={disabled || loading}
        className={`
          px-4 py-2 rounded font-medium transition-all duration-200
          ${loading || disabled
            ? 'bg-gray-500 text-gray-300 cursor-not-allowed'
            : 'bg-[#8F2FFE] text-white hover:bg-[#7A28E0] active:scale-95'
          }
        `}
      >
        {loading ? (
          <span className="flex items-center space-x-2">
            <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />
            <span>Convirtiendo...</span>
          </span>
        ) : (
          'Convertir a Orden'
        )}
      </button>

      {/* ✅ MOSTRAR ERRORES ESPECÍFICOS */}
      {error && (
        <div className="text-red-400 text-sm bg-red-900/20 p-2 rounded">
          {error}
        </div>
      )}
    </div>
  );
};
